/**
 * WarmForge — Build daily warmup tasks with unique sender logic and randomization
 * Inputs: { senders: [...], warmers: [...] }
 */

// Helpers
function getInputs(items) {
  if (items.length >= 2 && items[0].json.senders && items[1].json.warmers) {
    return { senders: items[0].json.senders, warmers: items[1].json.warmers };
  }
  if (items.length === 1 && items[0].json.senders && items[0].json.warmers) {
    return { senders: items[0].json.senders, warmers: items[0].json.warmers };
  }
  throw new Error('Missing senders or warmers input.');
}

function shuffle(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
}

function getNowET() {
  return new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
}

function getRandomDelayMs(minMinutes, maxMinutes) {
  const minMs = minMinutes * 60 * 1000;
  const maxMs = maxMinutes * 60 * 1000;
  return Math.floor(Math.random() * (maxMs - minMs + 1)) + minMs;
}

function isWithinETWindow(date, startHour = 9, endHour = 16) {
  const et = new Date(date.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const hour = et.getHours();
  return hour >= startHour && hour < endHour;
}

function getNextValidETTime(anchor, minDelayMins = 0) {
  let candidate = new Date(anchor.getTime() + minDelayMins * 60 * 1000);
  while (!isWithinETWindow(candidate)) {
    candidate = new Date(candidate.getTime() + 15 * 60 * 1000); // Add 15 min until within ET window
  }
  return candidate;
}

function dedupeByAddress(records, key) {
  return Object.values(
    records.reduce((acc, item) => {
      acc[item[key]] = item;
      return acc;
    }, {})
  );
}

function buildSchedule({ senders, warmers }) {
  const output = [];

  const uniqueSenders = dedupeByAddress(senders, 'sender_address');
  const uniqueWarmers = dedupeByAddress(warmers, 'warmer_address');

  const outboundCount = {};
  const maxSends = {};

  for (const s of uniqueSenders) {
    outboundCount[s.sender_address] = 0;
    maxSends[s.sender_address] = Number(s.max_daily_sends ?? 0);
  }

  const getThreadId = () => `t-${Date.now()}-${Math.floor(Math.random() * 1e6)}`;
  const getQID = () => `wf-${Date.now()}-${Math.floor(Math.random() * 1e6)}`;
  const now = getNowET();
  const threadTypes = ['single', 'thread'];
  let warmerIndex = 0;

  for (const sender of uniqueSenders) {
    const max = maxSends[sender.sender_address];
    let count = outboundCount[sender.sender_address];

    while (count < max) {
      const warmer = uniqueWarmers[warmerIndex % uniqueWarmers.length];
      warmerIndex++;

      if (sender.sender_address === warmer.warmer_address) continue;

      let replyType, threadDepth, projectedOutbounds, attempts = 0;

      do {
        replyType = threadTypes[Math.floor(Math.random() * threadTypes.length)];
        threadDepth = replyType === 'single' ? 2 : Math.floor(Math.random() * 3) * 2 + 2; // 2,4,6
        projectedOutbounds = Math.ceil(threadDepth / 2);
        attempts++;
        if (attempts > 10) break;
      } while (count + projectedOutbounds > max);

      if (count + projectedOutbounds > max) break;

      const threadId = getThreadId();
      let prevQID = null;
      let anchor = getNextValidETTime(now, Math.floor(Math.random() * 60));

      for (let i = 0; i < threadDepth; i++) {
        const direction = i % 2 === 0 ? 'outbound' : 'inbound';
        const qid = getQID();
        const isOutbound = direction === 'outbound';

        if (isOutbound) {
          if (outboundCount[sender.sender_address] >= max) break;
          outboundCount[sender.sender_address]++;
          count++;
        }

        const msg = {
          qid,
          parent_qid: prevQID,
          sid: sender.sid,
          wid: warmer.wid,
          thread_id: threadId,
          thread_index: i,
          thread_depth: threadDepth,
          reply_type: replyType,
          direction,
          sender_address: sender.sender_address,
          sender_name: sender.sender_name,
          warmer_address: warmer.warmer_address,
          warmer_name: warmer.warmer_name,
          domain: sender.domain,
          send_time: getNextValidETTime(anchor).toISOString(),
          created_at: new Date().toISOString(),
          schedule_window_et: '09:00–16:00',
          tz_anchor: 'America/New_York',
          engine: 'WarmForge',
          status: 'queued',
        };

        output.push({ json: msg });
        anchor = new Date(new Date(msg.send_time).getTime() + getRandomDelayMs(30, 180));
        prevQID = qid;
      }
    }
  }

  return output;
}

// ENTRY
const { senders, warmers } = getInputs(items);
shuffle(senders);
shuffle(warmers);
return buildSchedule({ senders, warmers });

