const senders = input.senders;
const warmers = input.warmers;

function shuffleArray(arr) {
  return arr
    .map(value => ({ value, sort: Math.random() }))
    .sort((a, b) => a.sort - b.sort)
    .map(({ value }) => value);
}

const outboundCount = {};
const maxSends = {};

for (const sender of senders) {
  outboundCount[sender.sender_address] = 0;
  maxSends[sender.sender_address] = Number(sender.max_daily_sends ?? 0);
}

const output = [];

for (const sender of senders) {
  const senderEmail = sender.sender_address;
  const max = maxSends[senderEmail];

  // Shuffle warmers for each sender to ensure randomization
  const shuffledWarmers = shuffleArray([...warmers]);

  for (const warmer of shuffledWarmers) {
    if (sender.sender_address === warmer.warmer_address) continue;

    if (outboundCount[senderEmail] < max) {
      output.push({
        json: {
          sender,
          warmer
        }
      });

      outboundCount[senderEmail]++;
    }

    if (outboundCount[senderEmail] >= max) break; // stop pairing for this sender
  }
}

return output;

// Inputs: [{ sender, warmer }, ...]
// Builds outbound/inbound message threads respecting max_daily_sends per sender

// Time helpers
function getNowET() {
  return new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
}

function getRandomDelayMs(minMinutes, maxMinutes) {
  const minMs = minMinutes * 60 * 1000;
  const maxMs = maxMinutes * 60 * 1000;
  return Math.floor(Math.random() * (maxMs - minMs + 1)) + minMs;
}

function isWithinETWindow(date, startHour = 9, endHour = 16) {
  const et = new Date(date.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const hour = et.getHours();
  return hour >= startHour && hour < endHour;
}

function getNextValidETTime(anchor, minDelayMins = 0) {
  let candidate = new Date(anchor.getTime() + minDelayMins * 60 * 1000);
  while (!isWithinETWindow(candidate)) {
    candidate = new Date(candidate.getTime() + 15 * 60 * 1000);
  }
  return candidate;
}

// Message generator
function getQID() {
  return `wf-${Date.now()}-${Math.floor(Math.random() * 1e6)}`;
}

function getThreadId() {
  return `t-${Date.now()}-${Math.floor(Math.random() * 1e6)}`;
}

// Main build function
function buildThreads(pairs) {
  const output = [];
  const now = getNowET();

  // Track how many outbounds each sender has used
  const outboundCount = {};
  const maxSends = {};

  for (const pair of pairs) {
    const sender = pair.sender;
    outboundCount[sender.sender_address] = 0;
    maxSends[sender.sender_address] = Number(sender.max_daily_sends ?? 0);
  }

  const threadTypes = ['single', 'thread'];

  for (const pair of pairs) {
    const { sender, warmer } = pair;
    const senderEmail = sender.sender_address;
    const maxAllowed = maxSends[senderEmail];
    let used = outboundCount[senderEmail];

    // Determine reply_type and threadDepth
    let replyType, threadDepth, projectedOutbounds;
    let attempts = 0;

    do {
      replyType = threadTypes[Math.floor(Math.random() * threadTypes.length)];
      threadDepth = replyType === 'single' ? 2 : Math.floor(Math.random() * 2) * 2 + 4; // 4 or 6
      projectedOutbounds = Math.ceil(threadDepth / 2);
      attempts++;
      if (attempts > 10) break;
    } while (used + projectedOutbounds > maxAllowed);

    if (used + projectedOutbounds > maxAllowed) continue;

    // Build the thread
    const threadId = getThreadId();
    let prevQID = null;
    let anchor = getNextValidETTime(now, Math.floor(Math.random() * 60));

    for (let i = 0; i < threadDepth; i++) {
      const direction = i % 2 === 0 ? 'outbound' : 'inbound';
      const isOutbound = direction === 'outbound';

      if (isOutbound && outboundCount[senderEmail] >= maxAllowed) break;

      const qid = getQID();

      const message = {
        qid,
        parent_qid: prevQID,
        sid: sender.sid,
        wid: warmer.wid,
        thread_id: threadId,
        thread_index: i,
        thread_depth: threadDepth,
        reply_type: replyType,
        direction,
        sender_address: sender.sender_address,
        sender_name: sender.sender_name,
        warmer_address: warmer.warmer_address,
        warmer_name: warmer.warmer_name,
        domain: sender.domain,
        send_time: getNextValidETTime(anchor).toISOString(),
        created_at: new Date().toISOString(),
        schedule_window_et: '09:00–16:00',
        tz_anchor: 'America/New_York',
        engine: 'WarmForge',
        status: 'queued'
      };

      output.push({ json: message });

      if (isOutbound) {
        outboundCount[senderEmail]++;
      }

      anchor = new Date(new Date(message.send_time).getTime() + getRandomDelayMs(30, 180));
      prevQID = qid;
    }
  }

  return output;
}

// Run it
return buildThreads(items.map(i => i.json));
